// --- TYPES --------------------------------------------------------------------

export type Category = "scholarship" | "grant" | "trade" | "other" | "local"

export interface Scholarship {
  id: number
  name: string
  slug: string
  category: Category
  amount: string
  deadline: string
  gpa: string
  renewable: boolean
  url: string
  tags: string[]
  eligibility: string
}

export interface LocalScholarship {
  id: string
  slug: string
  name: string
  state: string
  county: string
  city: string
  amount: string
  deadline: string
  eligibility: string
  url: string
  propublica_url: string | null
  tags: string[]
  category: "local"
  gpa: string
  renewable: boolean
}

// --- HELPERS ------------------------------------------------------------------

export const slugify = (s: string) =>
  s.toLowerCase().replace(/[^a-z0-9]+/g, "-").replace(/(^-|-$)/g, "")

