export const LOCAL_DATA: LocalScholarship[] = RAW_LOCAL.map(s => ({
  ...s,
  slug: s.state.toLowerCase() + "-" + s.id + "-" + s.name.toLowerCase().replace(/[^a-z0-9]+/g, "-").replace(/(^-|-$)/g, ""),
  category: "local" as const,
  gpa: "Varies",
  renewable: false, tags: [...s.tags] as string[],
}))

export const ALL_ITEMS = [...SCHOLARSHIPS, ...LOCAL_DATA] as (Scholarship | LocalScholarship)[]

export function getScholarshipBySlug(slug: string): Scholarship | undefined {
  return SCHOLARSHIPS.find(s => s.slug === slug)
}

export function getLocalBySlug(slug: string): LocalScholarship | undefined {
  return LOCAL_DATA.find(s => s.slug === slug)
}

export function getItemBySlug(slug: string) {
  return getScholarshipBySlug(slug) || getLocalBySlug(slug)
}
